using System;
using System.Linq;
using System.Linq.Expressions;

class Program
{
    static void Main(string[] args)
    {
        Console.WriteLine("LINQ ifadə ağacı təhlili...");
        var people = new[]
        {
            new Person { Name = "Ayxan", Age = 25 },
            new Person { Name = "Leyla", Age = 30 }
        }.AsQueryable();

        Expression<Func<Person, bool>> filter = p => p.Age > 25;
        var query = people.Where(filter);
        Console.WriteLine($"İfadə ağacı: {filter}");

        foreach (var person in query)
        {
            Console.WriteLine($"Ad: {person.Name}, Yaş: {person.Age}");
        }
    }
}

class Person
{
    public string Name { get; set; }
    public int Age { get; set; }
}
