// İfadə ağacı: p => p.Age > 25
// Ad: Leyla, Yaş: 30

using System;
using System.Collections.Generic;
using System.Linq;
using System.Linq.Expressions;

class CustomQueryProvider : IQueryProvider
{
    private readonly List<Person> _data;

    public CustomQueryProvider(List<Person> data)
    {
        _data = data;
    }

    public IQueryable CreateQuery(Expression expression)
    {
        return new CustomQueryable<Person>(this, expression);
    }

    public IQueryable<TElement> CreateQuery<TElement>(Expression expression)
    {
        return new CustomQueryable<TElement>(this, expression);
    }

    public object Execute(Expression expression)
    {
        return Execute<IEnumerable<Person>>(expression);
    }

    public TResult Execute<TResult>(Expression expression)
    {
        if (expression is MethodCallExpression methodCall && methodCall.Method.Name == "Where")
        {
            var lambda = (LambdaExpression)((UnaryExpression)methodCall.Arguments[1]).Operand;
            var predicate = (Func<Person, bool>)lambda.Compile();
            return (TResult)(object)_data.Where(predicate).ToList();
        }
        return (TResult)(object)_data.ToList();
    }
}

class CustomQueryable<T> : IQueryable<T>
{
    private readonly CustomQueryProvider _provider;
    private readonly Expression _expression;

    public CustomQueryable(CustomQueryProvider provider, Expression expression)
    {
        _provider = provider;
        _expression = expression;
    }

    public Type ElementType => typeof(T);
    public Expression Expression => _expression;
    public IQueryProvider Provider => _provider;

    public IEnumerator<T> GetEnumerator() => _provider.Execute<IEnumerable<T>>(_expression).GetEnumerator();
    System.Collections.IEnumerator System.Collections.IEnumerable.GetEnumerator() => GetEnumerator();
}

